def build_tree(preorder):
    if not preorder:
        return None
    root = TreeNode(preorder[0])
    queue = [(root, 0)]
    while queue:
        node, i = queue.pop(0)
        left_child = preorder[2*i+1] if 2*i+1 < len(preorder) else None
        right_child = preorder[2*i+2] if 2*i+2 < len(preorder) else None
        if left_child is not None:
            node.left = TreeNode(left_child)
            queue.append((node.left, 2*i+1))
        if right_child is not None:
            node.right = TreeNode(right_child)
            queue.append((node.right, 2*i+2))
    return root

class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

